/**
 * @summary Search TMDB for movies/TV shows
 */
export const getSearchTmdbUrl = (params: SearchTmdbParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/tmdb/search?${stringifiedParams}`
    : `/api/tmdb/search`;
};

export const searchTmdb = async (
  params: SearchTmdbParams,
  options?: RequestInit,
): Promise<TmdbSearchResult> => {
  return customFetch<TmdbSearchResult>(getSearchTmdbUrl(params), {
    ...options,
    method: "GET",
  });
};

